using System.Reflection;
using System.Runtime.InteropServices;

var runtimeDir = RuntimeEnvironment.GetRuntimeDirectory();

var depsDir = "/home/runner/.nuget/packages/microsoft.agents.ai/1.6.1/lib/net10.0/";
var meaiDir = "/home/runner/.nuget/packages/microsoft.extensions.ai/9.6.0/lib/net10.0/";
var meaiAbsDir = "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/9.6.0/lib/net10.0/";

var paths = Directory.GetFiles(runtimeDir, "*.dll").ToList();
paths.AddRange(Directory.GetFiles(depsDir, "*.dll"));
if (Directory.Exists(meaiDir)) paths.AddRange(Directory.GetFiles(meaiDir, "*.dll"));
if (Directory.Exists(meaiAbsDir)) paths.AddRange(Directory.GetFiles(meaiAbsDir, "*.dll"));

var resolver = new PathAssemblyResolver(paths);
using var mlc = new MetadataLoadContext(resolver);
var asm = mlc.LoadFromAssemblyPath(Path.Combine(depsDir, "Microsoft.Agents.AI.dll"));
foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
{
    Console.WriteLine(t.FullName);
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  {m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.Name}: {p.PropertyType.Name}");
    foreach (var c in t.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
}
EOF
