using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace ResearchAgent;

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
public sealed class ResearchTools
{
    private readonly HttpClient _httpClient;
    private readonly List<NoteEntry> _notes = [];

    public ResearchTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public IReadOnlyList<NoteEntry> Notes => _notes;

    [Description("Search the web for information on a given query. Returns a list of results with titles, snippets, and URLs.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            // Uses the Brave Search API when BRAVE_API_KEY is set;
            // otherwise falls back to simulated results so the app
            // remains runnable without external credentials.
            var apiKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");
            if (!string.IsNullOrEmpty(apiKey))
            {
                return await SearchBraveAsync(query, maxResults, apiKey);
            }

            return GenerateSimulatedResults(query, maxResults);
        }
        catch (Exception ex)
        {
            return [new SearchResult($"Search error: {ex.Message}", ex.Message, "")];
        }
    }

    [Description("Save a research note with a topic label and content. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("A short label or topic for this note")] string topic,
        [Description("The content of the note to save")] string content)
    {
        var entry = new NoteEntry(topic, content, DateTime.UtcNow);
        _notes.Add(entry);
        return $"Note #{_notes.Count} saved under topic \"{topic}\".";
    }

    [Description("Retrieve all saved research notes, optionally filtered by topic.")]
    public IReadOnlyList<NoteEntry> GetNotes(
        [Description("Optional topic filter (case-insensitive partial match). Leave empty to get all notes.")] string? topicFilter = null)
    {
        if (string.IsNullOrWhiteSpace(topicFilter))
        {
            return _notes;
        }

        return _notes
            .Where(n => n.Topic.Contains(topicFilter, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    private async Task<IReadOnlyList<SearchResult>> SearchBraveAsync(
        string query, int maxResults, string apiKey)
    {
        using var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={maxResults}");
        request.Headers.Add("X-Subscription-Token", apiKey);
        request.Headers.Add("Accept", "application/json");

        using var response = await _httpClient.SendAsync(request);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>();
        var results = new List<SearchResult>();

        if (json.TryGetProperty("web", out var web) &&
            web.TryGetProperty("results", out var webResults))
        {
            foreach (var item in webResults.EnumerateArray().Take(maxResults))
            {
                var title = item.GetProperty("title").GetString() ?? "";
                var snippet = item.TryGetProperty("description", out var desc)
                    ? desc.GetString() ?? ""
                    : "";
                var url = item.GetProperty("url").GetString() ?? "";
                results.Add(new SearchResult(title, snippet, url));
            }
        }

        return results;
    }

    private static List<SearchResult> GenerateSimulatedResults(string query, int maxResults)
    {
        // Deterministic simulated results so the agent loop is exercised
        // even without an API key.
        var results = new List<SearchResult>();
        var topics = new[]
        {
            ("Overview", "encyclopedia"),
            ("Recent developments", "news"),
            ("Research papers", "academic"),
            ("Industry analysis", "analysis"),
            ("Expert opinions", "expert"),
            ("Historical context", "history"),
            ("Statistics and data", "data"),
            ("Comparisons", "comparison"),
            ("Future outlook", "outlook"),
            ("Case studies", "case-study"),
        };

        for (int i = 0; i < Math.Min(maxResults, topics.Length); i++)
        {
            var (label, kind) = topics[i];
            results.Add(new SearchResult(
                Title: $"{label}: {query}",
                Snippet: $"This {kind} source covers key aspects of \"{query}\". "
                       + $"It discusses the main concepts, current state, and important details "
                       + $"that researchers and practitioners should be aware of regarding {query}.",
                Url: $"https://example.com/{kind}/{Uri.EscapeDataString(query.Replace(' ', '-'))}"));
        }

        return results;
    }
}

public sealed record SearchResult(
    [property: Description("Title of the search result")] string Title,
    [property: Description("A short snippet or summary of the page")] string Snippet,
    [property: Description("URL of the page")] string Url);

public sealed record NoteEntry(
    [property: Description("Topic label for this note")] string Topic,
    [property: Description("Content of the note")] string Content,
    [property: Description("When the note was saved (UTC)")] DateTime SavedAtUtc);

