using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using ResearchAgent;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// Dependency injection
// ---------------------------------------------------------------------------
var services = new ServiceCollection();

services.AddLogging(b => b
    .AddConsole()
    .SetMinimumLevel(LogLevel.Warning));

services.AddHttpClient();

services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var httpClient = sp.GetRequiredService<IHttpClientFactory>().CreateClient();
var tools = new ResearchTools(httpClient);

var aiTools = new List<AITool>
{
    AIFunctionFactory.Create(tools.SearchWebAsync),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

// ---------------------------------------------------------------------------
// Agent
// ---------------------------------------------------------------------------
const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic the user
    provides by using your available tools.

    Workflow:
    1. Break the topic into 2-3 sub-questions that cover different angles.
    2. For each sub-question, use the SearchWeb tool to find information.
    3. After reviewing search results, use SaveNote to record key findings
       with a descriptive topic label.
    4. Once you have gathered enough information (at least 3 notes),
       use GetNotes to review everything you have collected.
    5. Produce a final summary that synthesizes all your notes into a
       coherent, well-structured research brief with sections and citations.

    Guidelines:
    - Always cite sources by URL when available.
    - Be factual and objective.
    - If search results are insufficient, note the gaps in your summary.
    """;

var agent = new ChatClientAgent(
    sp.GetRequiredService<IChatClient>(),
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "Researches topics by searching the web and taking notes",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = aiTools,
        },
    },
    sp.GetRequiredService<ILoggerFactory>());

// Set the instructions via the simpler constructor overload's backing field
// by re-creating with the full ctor that accepts instructions directly.
agent = new ChatClientAgent(
    sp.GetRequiredService<IChatClient>(),
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: aiTools,
    loggerFactory: sp.GetRequiredService<ILoggerFactory>());

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║         🔍 Research Agent                   ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to    ║");
Console.WriteLine("║  exit.                                      ║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
