    1. Break the topic into 2-3 sub-questions that cover different angles.
    2. For each sub-question, use the SearchWeb tool to find information.
    3. After reviewing search results, use SaveNote to record key findings
       with a descriptive topic label.
    4. Once you have gathered enough information (at least 3 notes),
       use GetNotes to review everything you have collected.
    5. Produce a final summary that synthesizes all your notes into a
       coherent, well-structured research brief with sections and citations.

    Guidelines:
    - Always cite sources by URL when available.
    - Be factual and objective.
    - If search results are insufficient, note the gaps in your summary.
    """;

var agent = new ChatClientAgent(
    sp.GetRequiredService<IChatClient>(),
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: aiTools,
    loggerFactory: sp.GetRequiredService<ILoggerFactory>());

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║         🔍 Research Agent                   ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to    ║");
Console.WriteLine("║  exit.                                      ║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(input))
    {
        continue;
    }

    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase) ||
        input.Equals("exit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching... (the agent will search the web and take notes)\n");
    Console.ResetColor();

    try
    {
        var runOptions = new ChatClientAgentRunOptions(new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = aiTools,
        });

        var response = await agent.RunAsync(
            $"Please research the following topic thoroughly: {input}",
            session,
            runOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══\n");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();

        if (tools.Notes.Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.WriteLine($"📝 {tools.Notes.Count} note(s) were saved during this research session.");
            Console.ResetColor();
        }

        if (response.Usage is { } usage)
        {
            Console.ForegroundColor = ConsoleColor.DarkGray;
            Console.WriteLine($"Tokens — input: {usage.InputTokenCount}, output: {usage.OutputTokenCount}, total: {usage.TotalTokenCount}");
            Console.ResetColor();
        }

        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

